
.lf-stat__head {
  display: flex;
  align-items: center;
  gap: 7px;
  margin-bottom: 6px;
}
.lf-stat__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  height: 24px;
  border: 2px solid var(--lf-ink);
  border-radius: var(--lf-radius-pill);
  color: var(--lf-ink);
}
.lf-stat__label {
  font-family: var(--lf-font-display);
  font-size: 13px;
  font-weight: 600;
  color: var(--lf-text);
}
.lf-stat__value {
  margin-left: auto;
  font-family: var(--lf-font-display);
  font-weight: 700;
  font-size: 14px;
  color: var(--lf-text);
}
.lf-stat__suffix {
  margin-left: 1px;
  font-size: 11px;
  color: var(--lf-text-secondary);
}
.lf-stat__track {
  position: relative;
  height: 13px;
  border: 2px solid var(--lf-ink);
  border-radius: var(--lf-radius-pill);
  background: var(--lf-surface-sunken);
  overflow: hidden;
}
.lf-stat__fill {
  position: relative;
  height: 100%;
  border-radius: var(--lf-radius-pill);
  transition: width 0.6s var(--lf-ease-out);
  overflow: hidden;
}
.lf-stat__shine {
  position: absolute;
  inset: 0 0 50% 0;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.55), transparent);
  border-radius: inherit;
}
.lf-stat--compact .lf-stat__head { margin-bottom: 4px; }
.lf-stat--compact .lf-stat__track { height: 10px; }
.lf-stat--compact .lf-stat__icon { width: 20px; height: 20px; }
