
.lf-topbar {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 12px;
  background: var(--lf-surface);
  border-bottom: 2.5px solid var(--lf-ink);
  z-index: 2;
}
.lf-topbar__left {
  display: flex;
  align-items: center;
  gap: 8px;
  min-width: 0;
}
.lf-topbar__logo {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 38px;
  height: 38px;
  border: 2.5px solid var(--lf-ink);
  border-radius: var(--lf-radius-sm);
  background: var(--lf-peach);
  color: var(--lf-ink);
  box-shadow: var(--lf-shadow-chunky-sm);
}
.lf-topbar__titles {
  display: flex;
  flex-direction: column;
  min-width: 0;
}
.lf-topbar__shop {
  font-family: var(--lf-font-display);
  font-weight: 700;
  font-size: 15px;
  color: var(--lf-text);
  line-height: 1.1;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.lf-topbar__day {
  font-size: 11px;
  color: var(--lf-text-secondary);
  font-weight: 600;
}
.lf-topbar__env {
  margin-left: auto;
}
.lf-topbar__actions {
  display: flex;
  gap: 6px;
}
.lf-topbar__btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 34px;
  height: 34px;
  border: 2.5px solid var(--lf-ink);
  border-radius: var(--lf-radius-pill);
  background: var(--lf-surface-soft);
  color: var(--lf-ink);
  box-shadow: var(--lf-shadow-chunky-sm);
  transition: transform var(--lf-dur) var(--lf-ease-bounce), background var(--lf-dur);
}
.lf-topbar__btn:hover {
  background: var(--lf-butter);
  transform: translateY(-2px);
}
.lf-topbar__btn:active {
  transform: translateY(1px);
  box-shadow: 1px 1px 0 var(--lf-ink-shadow);
}
