
.lf-confirm {
  position: absolute;
  inset: 0;
  z-index: var(--lf-z-toast);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 24px;
}
.lf-confirm__scrim {
  position: absolute;
  inset: 0;
  background: rgba(91, 74, 82, 0.38);
  backdrop-filter: blur(3px);
}
.lf-confirm__panel {
  position: relative;
  width: 100%;
  max-width: 300px;
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  gap: 8px;
  padding: 22px 20px 18px;
  border: 3px solid var(--lf-ink);
  border-radius: var(--lf-radius-xl);
  background: var(--lf-surface);
  box-shadow: var(--lf-shadow-float);
}
.lf-confirm__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 56px;
  height: 56px;
  border: 3px solid var(--lf-ink);
  border-radius: var(--lf-radius-pill);
  background: var(--lf-butter);
  color: var(--lf-ink);
  box-shadow: var(--lf-shadow-chunky);
  transform: rotate(-4deg);
}
.lf-confirm__panel--danger .lf-confirm__icon {
  background: var(--lf-error);
  color: #fff;
}
.lf-confirm__title {
  font-size: 18px;
  font-weight: 700;
}
.lf-confirm__msg {
  font-size: 13px;
  line-height: 1.6;
  color: var(--lf-text-secondary);
}
.lf-confirm__actions {
  display: flex;
  gap: 10px;
  margin-top: 8px;
}

.lf-confirm-enter-active .lf-confirm__panel {
  animation: lf-pop-in var(--lf-dur) var(--lf-ease-bounce);
}
.lf-confirm-enter-active,
.lf-confirm-leave-active {
  transition: opacity var(--lf-dur) var(--lf-ease-soft);
}
.lf-confirm-enter-from,
.lf-confirm-leave-to {
  opacity: 0;
}
