
.lf-overview {
  margin: 0 12px 12px;
}
.lf-overview__head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 9px;
}
.lf-overview__title {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: 15px;
  font-weight: 700;
}
.lf-overview__more {
  display: inline-flex;
  align-items: center;
  gap: 2px;
  padding: 4px 10px;
  border: 2px solid var(--lf-ink);
  border-radius: var(--lf-radius-pill);
  background: var(--lf-surface);
  font-family: var(--lf-font-display);
  font-size: 12px;
  font-weight: 600;
  color: var(--lf-text-secondary);
  box-shadow: var(--lf-shadow-chunky-sm);
  transition: background var(--lf-dur), transform var(--lf-dur) var(--lf-ease-bounce);
}
.lf-overview__more:hover { background: var(--lf-butter); transform: translateX(2px); }

.lf-overview__env {
  display: flex;
  flex-wrap: wrap;
  gap: 7px;
  margin-bottom: 11px;
}

.lf-overview__grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 9px;
}
.lf-overview__cell {
  display: flex;
  align-items: center;
  gap: 9px;
  padding: 10px 11px;
}
.lf-overview__cell:nth-child(5) {
  grid-column: span 2;
}
.lf-overview__cell-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 32px;
  height: 32px;
  flex-shrink: 0;
  border: 2px solid var(--lf-ink);
  border-radius: var(--lf-radius-sm);
  color: var(--lf-ink);
}
.lf-overview__cell-body {
  display: flex;
  flex-direction: column;
  min-width: 0;
}
.lf-overview__cell-label {
  font-size: 11px;
  color: var(--lf-text-secondary);
  font-weight: 600;
}
.lf-overview__cell-value {
  font-family: var(--lf-font-display);
  font-weight: 700;
  font-size: 16px;
  color: var(--lf-text);
}
.lf-overview__cell-bar {
  width: 46px;
  height: 8px;
  margin-left: auto;
  border: 2px solid var(--lf-ink);
  border-radius: var(--lf-radius-pill);
  background: var(--lf-surface-sunken);
  overflow: hidden;
}
.lf-overview__cell:nth-child(5) .lf-overview__cell-bar {
  width: 100%;
  max-width: 180px;
}
.lf-overview__cell-fill {
  display: block;
  height: 100%;
  border-radius: var(--lf-radius-pill);
  transition: width 0.6s var(--lf-ease-out);
}
