
.lf-set__group {
  margin: 14px 0 8px;
  font-family: var(--lf-font-display);
  font-size: 13px;
  color: var(--lf-text-secondary);
}
.lf-set__group:first-child { margin-top: 0; }

.lf-set__row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  padding: 11px 13px;
  margin-bottom: 8px;
  border: 2.5px solid var(--lf-ink);
  border-radius: var(--lf-radius-md);
  background: var(--lf-surface);
  box-shadow: var(--lf-shadow-chunky-sm);
}
.lf-set__row--col {
  flex-wrap: wrap;
}
.lf-set__label {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  font-family: var(--lf-font-display);
  font-weight: 600;
  font-size: 14px;
  color: var(--lf-text);
}

.lf-set__switch {
  position: relative;
  width: 50px;
  height: 28px;
  border: 2.5px solid var(--lf-ink);
  border-radius: var(--lf-radius-pill);
  background: var(--lf-surface-sunken);
  transition: background var(--lf-dur) var(--lf-ease-soft);
  cursor: pointer;
}
.lf-set__switch--on {
  background: var(--lf-mint);
}
.lf-set__checkbox {
  position: absolute;
  inset: 0;
  margin: 0;
  opacity: 0;
  cursor: pointer;
}
.lf-set__knob {
  position: absolute;
  top: 2px;
  left: 2px;
  width: 20px;
  height: 20px;
  background: var(--lf-surface);
  border: 2px solid var(--lf-ink);
  border-radius: var(--lf-radius-pill);
  transition: transform var(--lf-dur) var(--lf-ease-bounce);
}
.lf-set__switch--on .lf-set__knob {
  transform: translateX(22px);
}

.lf-set__range {
  flex: 1;
  min-width: 140px;
  accent-color: var(--lf-strawberry);
}
.lf-set__speed {
  font-family: var(--lf-font-display);
  font-weight: 700;
  font-size: 13px;
  color: var(--lf-text);
}

.lf-set__accents {
  display: flex;
  gap: 10px;
}
.lf-set__accent {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  border: 2.5px solid var(--lf-ink);
  border-radius: var(--lf-radius-pill);
  color: var(--lf-ink);
  box-shadow: var(--lf-shadow-chunky-sm);
  transition: transform var(--lf-dur) var(--lf-ease-bounce);
}
.lf-set__accent:hover { transform: translateY(-2px) scale(1.05); }
.lf-set__accent--on { transform: scale(1.1); }

.lf-set__about {
  font-size: 13px;
  line-height: 1.7;
  color: var(--lf-text-secondary);
}
